broken_code:
use tracing::{info, instrument};

#[instrument]
async fn handle_request(request_id: u64) {
    info!("start");
    tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
    // If two requests are concurrent, this span may attach to the
    // wrong parent because the thread-local span context can be
    // overwritten when the executor switches tasks.
    info!("processing");
    tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
    info!("done");
}

#[tokio::main]
async fn main() {
    tracing_subscriber::fmt::init();
    // Run two requests concurrently — spans may be confused
    tokio::join!(
        handle_request(1),
        handle_request(2),
    );
}

error_message:
// No compile error. The issue is subtle: without proper async span propagation,
// the current span stored in thread-local storage can switch between tasks
// at await points. #[instrument] on async fns correctly uses Instrument to
// attach the span to the Future itself — this is actually the correct pattern.
// The common MISTAKE is manually calling span.enter() in async code.

fixed_code:
use tracing::{info, instrument, Instrument, span, Level};

// CORRECT: #[instrument] on async fn automatically wraps the Future with
// the span, so the span follows the task across thread hops
#[instrument(fields(request_id = request_id))]
async fn handle_request(request_id: u64) {
    info!("start");
    tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
    info!("processing");
    do_subtask(request_id).await;
    info!("done");
}

// CORRECT: use .instrument() on futures/tasks to propagate span
async fn do_subtask(id: u64) {
    let span = span!(Level::DEBUG, "subtask", id);
    async move {
        info!("subtask running");
        tokio::time::sleep(tokio::time::Duration::from_millis(5)).await;
        info!("subtask done");
    }
    .instrument(span)
    .await;
}

// WRONG pattern (do NOT do this in async code):
// async fn bad_span_usage() {
//     let span = span!(Level::INFO, "my-span");
//     let _guard = span.enter();  // guard is NOT Send, causes compile errors
//     some_async_call().await;    // span may be wrong after yield
// }

#[tokio::main]
async fn main() {
    tracing_subscriber::fmt::init();
    tokio::join!(
        handle_request(1),
        handle_request(2),
    );
}

