fixed_code:
use tracing::{info, instrument, span, Level, Instrument};

// Option A: use #[instrument] — cleanest for whole functions
#[instrument]
async fn traced_work_a() {
    info!("starting work");
    tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
    info!("work done");
}

// Option B: use .instrument() on the future — for inline spans
async fn traced_work_b() {
    info!("before span");
    async {
        info!("inside span");
        tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
        info!("span done");
    }
    .instrument(span!(Level::INFO, "work"))
    .await;
}

// Option C: enter() only within a synchronous block, exit before any await
async fn traced_work_c() {
    {
        let span = span!(Level::INFO, "sync-part");
        let _guard = span.enter();  // OK: guard dropped before await
        info!("synchronous setup done");
    }  // guard dropped here
    tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
}

#[tokio::main]
async fn main() {
    tracing_subscriber::fmt::init();
    tokio::spawn(traced_work_a()).await.unwrap();
    tokio::spawn(traced_work_b()).await.unwrap();
    tokio::spawn(traced_work_c()).await.unwrap();
}

