use tracing::{info, instrument};

#[instrument]
async fn parent_task() {
    info!("parent starting");
    // Spawned task does NOT inherit the current span
    tokio::spawn(async {
        info!("child working");  // appears at root level, not under parent span
        tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
    });
    info!("parent done");
}

#[tokio::main]
async fn main() {
    tracing_subscriber::fmt::init();
    parent_task().await;
    tokio::time::sleep(tokio::time::Duration::from_millis(50)).await;  // wait for child
}

error_message:
// No compile error. The spawned closure runs in a new task without the parent
// span in scope, so child spans appear at the root level instead of nested
// under `parent_task`.

fixed_code:
use tracing::{info, instrument, Instrument};

#[instrument]
async fn parent_task() {
    info!("parent starting");

    // Capture the current span BEFORE spawning, then instrument the task with it
    let current_span = tracing::Span::current();

    let handle = tokio::spawn(
        async {
            info!("child working");  // now appears nested under parent span
            tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
            info!("child done");
        }
        .instrument(current_span)  // propagate parent span into the spawned task
    );

    info!("parent done");
    handle.await.unwrap();
}

#[tokio::main]
async fn main() {
    tracing_subscriber::fmt::init();
    parent_task().await;
}

