use tracing::{info, instrument, warn};

async fn validate(data: &str) -> bool {
    info!("validating");  // request_id NOT visible here
    !data.is_empty()
}

async fn store(data: &str) {
    info!("storing");  // request_id NOT visible here either
}

#[instrument(fields(request_id = request_id))]  // sets field on THIS span
async fn handle(request_id: u64, data: &str) {
    info!("handling");  // request_id visible here
    if !validate(data).await {
        warn!("invalid data");
        return;
    }
    store(data).await;
    info!("complete");
}

error_message:
// No compile error. The issue: request_id is recorded on the `handle` span
// but child spans created by validate/store don't inherit fields from parents.
// In tracing, fields belong to a specific span, not to all nested spans.

fixed_code:
use tracing::{info, instrument, warn};

// Child spans automatically appear NESTED under the parent in trace output —
// the relationship is structural. Fields are per-span but the nesting is visible.
#[instrument(skip(data))]
async fn validate(data: &str) -> bool {
    info!("validating");  // appears nested under `handle`'s span
    !data.is_empty()
}

#[instrument(skip(data))]
async fn store(data: &str) {
    info!("storing");  // appears nested under `handle`'s span
}

#[instrument(fields(request_id = request_id), skip(data))]
async fn handle(request_id: u64, data: &str) {
    info!("handling request");
    // request_id is on this span; child spans are nested under it in the trace tree
    if !validate(data).await {
        warn!(request_id, "invalid data");  // add request_id explicitly when needed
        return;
    }
    store(data).await;
    info!("request complete");
}

#[tokio::main]
async fn main() {
    tracing_subscriber::fmt::init();
    handle(42, "hello").await;
    handle(43, "").await;
}

