use tracing::{info, span, Level};
use std::thread;

fn cpu_work(n: u32) -> u32 {
    info!("cpu_work called");  // span context NOT available here
    n * n
}

#[tokio::main]
async fn main() {
    tracing_subscriber::fmt::init();
    let root_span = span!(Level::INFO, "root");
    let _guard = root_span.enter();

    info!("starting");
    // tokio::task::spawn_blocking runs on a different thread pool
    // span context is NOT automatically propagated
    let result = tokio::task::spawn_blocking(|| cpu_work(5)).await.unwrap();
    info!(result, "done");
}

error_message:
// No compile error. But `cpu_work` runs without a span context — its
// info! event appears at the root tracing level, disconnected from the
// parent span that was active when spawn_blocking was called.

fixed_code:
use tracing::{info, instrument, span, Level, Instrument};

// CPU-bound work running in spawn_blocking — no async, but can receive a span
fn cpu_work(n: u32) -> u32 {
    info!("cpu_work called with n={}", n);
    n * n
}

#[tokio::main]
async fn main() {
    tracing_subscriber::fmt::init();

    // Capture the current span before crossing the thread boundary
    let current_span = span!(Level::INFO, "request", operation = "compute");

    let result = {
        let span_for_blocking = current_span.clone();
        tokio::task::spawn_blocking(move || {
            // Enter the span on the blocking thread
            let _guard = span_for_blocking.enter();
            cpu_work(5)
        })
        .await
        .unwrap()
    };

    let _guard = current_span.enter();
    info!(result, "blocking task complete");
}
